const body = $input.first().json.body;
const request_id = body.request_id || 'unknown';
const vision_result = body.vision_result || null;
const text_result = body.text_result || null;
const trace = body.trace || [];

const sysPrompt = 'You are a report writer. Use ONLY the provided tool outputs. Do not hallucinate.\nOUTPUT: JSON only. No markdown, no code fences.\nYou MUST provide a non-empty "summary" (1-2 sentence human-readable summary of findings).\nYou MUST provide at least one "recommendations" entry based on the findings.\nSCHEMA: {"request_id":"","summary":"...","findings":{"vision":{"top_objects":[],"details":[]},"text":{"label":null,"confidence":null,"entities":[]}},"recommendations":["..."],"trace":[],"errors":[]}';

let user = 'request_id=' + request_id;
if (vision_result) {
  const objs = (vision_result.detections || []).flatMap(d => (d.objects || []).map(o => o.label + ':' + (o.score || 0).toFixed(2))).slice(0, 10);
  user += ' VISION=[' + objs.join(',') + ']';
} else {
  user += ' VISION=NONE';
}
if (text_result) {
  const c = text_result.classification || {};
  user += ' TEXT=' + (c.label || 'unknown') + ':' + (c.confidence || 0).toFixed(2);
  const ents = (text_result.entities || []).map(e => e.type + ':' + e.value).slice(0, 10);
  if (ents.length > 0) user += ' ENTITIES=[' + ents.join(',') + ']';
} else {
  user += ' TEXT=NONE';
}
user += ' TRACE=' + JSON.stringify(trace);
user += ' Write summary and at least one recommendation.';

return [{ json: { request_id, trace, vision_result, text_result, llm_payload: { model: 'local-llama', messages: [{ role: 'system', content: sysPrompt }, { role: 'user', content: user }], temperature: 0.1, max_tokens: 512 } } }];

const buildInput = $('BuildReportInputs').first().json;
const llmResp = $input.first().json;
let report;
try {
  let content = llmResp.choices[0].message.content;
  content = content.replace(/^[\s\S]*?\{/, '{');
  const lastBrace = content.lastIndexOf('}');
  if (lastBrace !== -1) content = content.substring(0, lastBrace + 1);
  report = JSON.parse(content);
} catch (e) {
  report = { request_id: buildInput.request_id, summary: '', findings: {}, recommendations: [], trace: buildInput.trace || [], errors: ['LLM parse error: ' + e.message] };
}

report.request_id = report.request_id || buildInput.request_id;

// Ensure summary is non-empty; generate fallback from tool outputs
if (typeof report.summary !== 'string' || !report.summary.trim()) {
  const parts = [];
  const vr = buildInput.vision_result;
  if (vr && vr.detections) {
    const labels = vr.detections.flatMap(d => (d.objects || []).map(o => o.label));
    if (labels.length > 0) parts.push('Vision detected: ' + [...new Set(labels)].slice(0, 5).join(', '));
  }
  const tr = buildInput.text_result;
  if (tr && tr.classification) {
    parts.push('Text classified as ' + tr.classification.label + ' (' + (tr.classification.confidence * 100).toFixed(0) + '% confidence)');
  }
  report.summary = parts.length > 0 ? parts.join('. ') + '.' : 'Analysis completed with no significant findings.';
}

// Ensure findings structure
if (!report.findings || typeof report.findings !== 'object') report.findings = {};
if (!report.findings.vision || typeof report.findings.vision !== 'object') report.findings.vision = { top_objects: [], details: [] };
if (!Array.isArray(report.findings.vision.top_objects)) report.findings.vision.top_objects = [];
if (!Array.isArray(report.findings.vision.details)) report.findings.vision.details = [];

// Fill vision top_objects from source data if LLM left them empty
const vr = buildInput.vision_result;
if (vr && vr.detections && report.findings.vision.top_objects.length === 0) {
  const labels = vr.detections.flatMap(d => (d.objects || []).map(o => o.label));
  report.findings.vision.top_objects = [...new Set(labels)].slice(0, 10);
}

// Ensure text findings structure
if (!report.findings.text || typeof report.findings.text !== 'object') report.findings.text = { label: null, confidence: null, entities: [] };
const tr = buildInput.text_result;
if (tr && tr.classification) {
  if (!report.findings.text.label) report.findings.text.label = tr.classification.label;
  if (!report.findings.text.confidence) report.findings.text.confidence = tr.classification.confidence;
}
if (report.findings.text.label === undefined) report.findings.text.label = null;
if (report.findings.text.confidence === undefined) report.findings.text.confidence = null;
if (!Array.isArray(report.findings.text.entities)) report.findings.text.entities = [];

// Fill entities from text_result if LLM left them empty
if (tr && Array.isArray(tr.entities) && report.findings.text.entities.length === 0) {
  report.findings.text.entities = tr.entities.map(e => e.value || e);
}

// Ensure recommendations is non-empty; generate fallback
if (!Array.isArray(report.recommendations) || report.recommendations.length === 0) {
  report.recommendations = [];
  if (vr && vr.detections) {
    const hasPersons = vr.detections.some(d => (d.objects || []).some(o => o.label === 'person'));
    if (hasPersons) report.recommendations.push('Review detected persons in the image for safety compliance.');
    const allLabels = vr.detections.flatMap(d => (d.objects || []).map(o => o.label));
    if (allLabels.length > 0) report.recommendations.push('Verify detected objects (' + [...new Set(allLabels)].slice(0, 3).join(', ') + ') against expected conditions.');
  }
  if (tr && tr.classification) {
    const lbl = tr.classification.label;
    if (lbl === 'safety_hazard') report.recommendations.push('Immediate safety review recommended based on text classification.');
    else if (lbl === 'maintenance_issue') report.recommendations.push('Schedule maintenance inspection based on text classification.');
    else if (lbl === 'equipment_failure') report.recommendations.push('Investigate potential equipment failure indicated by text analysis.');
    else report.recommendations.push('Continue monitoring; text classified as ' + lbl + '.');
  }
  if (report.recommendations.length === 0) report.recommendations.push('No actionable items identified; continue standard monitoring.');
}

if (!Array.isArray(report.trace)) report.trace = buildInput.trace || [];
if (!Array.isArray(report.errors)) report.errors = [];

return [{ json: report }];
